4781 
4782   // Canonicalize common cmp+sel operand as TVal.
4783   if (CmpLHS == FVal) {
4784     std::swap(TVal, FVal);
4785     Pred = ICmpInst::getInversePredicate(Pred);
4786   }
4787 
4788   // A vector select may be shuffling together elements that are equivalent
4789   // based on the max/min/select relationship.
4790   Value *X = CmpLHS, *Y = CmpRHS;
