4792   auto *Shuf = dyn_cast<ShuffleVectorInst>(FVal);
4793   if (Shuf && Shuf->isSelect()) {
4794     if (Shuf->getOperand(0) == Y)
4795       FVal = Shuf->getOperand(1);
4796     else if (Shuf->getOperand(1) == Y)
4797       FVal = Shuf->getOperand(0);
4798     else
4799       return nullptr;
4800     PeekedThroughSelectShuffle = true;
4801   }
4802 
4803   // (X pred Y) ? X : max/min(X, Y)
4804   auto *MMI = dyn_cast<MinMaxIntrinsic>(FVal);
