4829 
4830   // (X != Y) ? X : max/min(X, Y) --> X
4831   if (Pred == CmpInst::ICMP_NE)
4832     return X;
4833 
4834   // (X <  Y) ? X : max(X, Y) --> X
4835   // (X <= Y) ? X : max(X, Y) --> X
4836   // (X >  Y) ? X : min(X, Y) --> X
4837   // (X >= Y) ? X : min(X, Y) --> X
4838   ICmpInst::Predicate InvPred = CmpInst::getInversePredicate(Pred);
4839   if (MMPred == CmpInst::getStrictPredicate(InvPred))
4840     return X;
4841 
4842   return nullptr;
