4416     // Having a poison generating annotation means that it can be poison
4417     // without any of the given values being poison.
4418     if (I->hasPoisonGeneratingAnnotations())
4419       return false;
4420 
4421     // Filtering out the assumed poison values, so only the relevant ones are
4422     // brought forward to the next recursive call.
4423     SmallVector<const Value *, 2> ValuesImplyingPoison;
4424     copy_if(ValuesAssumedPoison, std::back_inserter(ValuesImplyingPoison),
4425             [V](const auto *P) { return impliesPoison(P, V); });
4426 
4427     if (ValuesImplyingPoison.empty())
4428       return false;
4429 
4430     const unsigned MaxDepth = 2;
4431     if (Depth > MaxDepth)
4432       return false;
4433 
4434     return all_of(I->operand_values(),
4435                   [&ValuesImplyingPoison, Depth](const auto *Op) {
4436                     return areTheseAllTheValuesThatMayCausePoisonInValue(
4437                         ValuesImplyingPoison, Op, Depth + 1);
4438                   });
4439   }
4440 
4441   // A constant can't cause poison, unless it is itself a poison.
4442   if (const Constant *C = dyn_cast<Constant>(V))
4443     return !C->containsUndefOrPoisonElement();
