4587         return ConstantInt::get(I->getType(), 0);
4588       }
4589     }
4590 
4591     if (isa<GetElementPtrInst>(I)) {
4592       // getelementptr x, 0 -> x.
4593       // This never returns poison, even if inbounds is set.
4594       if (NewOps.size() == 2 && match(NewOps[1], m_Zero()))
4595         return NewOps[0];
4596     }
4597 
4598     if (SelectInst *SI = dyn_cast<SelectInst>(I)) {
4599       Value *SimplifiedValue = nullptr;
4600       Value *Cond = SI->getCondition();
4601 
4602       // The select couldn't act as a poison barrirer for its old operands and
4603       // the new condition can't be more poisonus than the old one.
4604       if (impliesPoison(NewOps[0], Cond) &&
4605           impliesPoison(SI->getTrueValue(), Cond) &&
4606           impliesPoison(SI->getFalseValue(), Cond)) {
4607 
4608         // Cond ? V : V -> V
4609         // We know that after replacement both of the operands will be the same.
4610         // We have to make sure that no refinment happens. This is done by
4611         // checking if the select condition can only be poison if any of the
4612         // arms are poison. If the condition could be poison and neither of the
4613         // arms would be poison, returning the less poisonus value would be a
4614         // refinment.
4615         if (NewOps[1] == NewOps[2] &&
4616             areTheseAllTheValuesThatMayCausePoisonInValue(
4617                 {SI->getFalseValue(), SI->getTrueValue(), NewOps[1]}, Cond))
4618           SimplifiedValue = NewOps[1];
4619 
4620         // TODO: Implement more non refining select optimizations here!
4621 
4622         // If we could do any simplification check if it has any poison
4623         // generating flags and handle them.
4624         if (SimplifiedValue) {
4625           if (SI->hasPoisonGeneratingAnnotations()) {
4626             if (!DropFlags)
4627               return nullptr;
4628             DropFlags->push_back(SI);
4629           }
4630           return SimplifiedValue;
4631         }
4632       }
4633     }
4634   } else {
4635     // The simplification queries below may return the original value. Consider:
4636     //   %div = udiv i32 %arg, %arg2
4637     //   %mul = mul nsw i32 %div, %arg2
4638     //   %cmp = icmp eq i32 %mul, %arg
4639     //   %sel = select i1 %cmp, i32 %div, i32 undef
4640     // Replacing %arg by %mul, %div becomes "udiv i32 %mul, %arg2", which
4641     // simplifies back to %arg. This can only happen because %mul does not
4642     // dominate %div. To ensure a consistent return value contract, we make sure
4643     // that this case returns nullptr as well.
4644     auto PreventSelfSimplify = [V](Value *Simplified) {
4645       return Simplified != V ? Simplified : nullptr;
4646     };
