4882 /// integer comparison.
4883 static Value *simplifySelectWithICmpCond(Value *CondVal, Value *TrueVal,
4884                                          Value *FalseVal,
4885                                          const SimplifyQuery &Q,
4886                                          unsigned MaxRecurse) {
4887   CmpPredicate Pred;
4888   Value *CmpLHS, *CmpRHS;
4889   if (!match(CondVal, m_ICmp(Pred, m_Value(CmpLHS), m_Value(CmpRHS))))
4890     return nullptr;
4891 
4892   if (Value *V = simplifyCmpSelOfMaxMin(CmpLHS, CmpRHS, Pred, TrueVal, FalseVal))
4893     return V;
4894 
4895   // Canonicalize ne to eq predicate.
4896   if (Pred == ICmpInst::ICMP_NE) {
4897     Pred = ICmpInst::ICMP_EQ;
4898     std::swap(TrueVal, FalseVal);
4899   }
4900 
4901   // Check for integer min/max with a limit constant:
4902   // X > MIN_INT ? X : MIN_INT --> X
4903   // X < MAX_INT ? X : MAX_INT --> X
4904   if (TrueVal->getType()->isIntOrIntVectorTy()) {
4905     Value *X, *Y;
4906     SelectPatternFlavor SPF =
4907         matchDecomposedSelectPattern(cast<ICmpInst>(CondVal), TrueVal, FalseVal,
4908                                      X, Y)
4909             .Flavor;
4910     if (SelectPatternResult::isMinOrMax(SPF) && Pred == getMinMaxPred(SPF)) {
4911       APInt LimitC = getMinMaxLimit(getInverseMinMaxFlavor(SPF),
4912                                     X->getType()->getScalarSizeInBits());
4913       if (match(Y, m_SpecificInt(LimitC)))
