4915     }
4916   }
4917 
4918   if (Pred == ICmpInst::ICMP_EQ && match(CmpRHS, m_Zero())) {
4919     Value *X;
4920     const APInt *Y;
4921     if (match(CmpLHS, m_And(m_Value(X), m_APInt(Y))))
4922       if (Value *V = simplifySelectBitTest(TrueVal, FalseVal, X, Y,
4923                                            /*TrueWhenUnset=*/true))
4924         return V;
4925 
4926     // Test for a bogus zero-shift-guard-op around funnel-shift or rotate.
4927     Value *ShAmt;
4928     auto isFsh = m_CombineOr(m_FShl(m_Value(X), m_Value(), m_Value(ShAmt)),
4929                              m_FShr(m_Value(), m_Value(X), m_Value(ShAmt)));
4930     // (ShAmt == 0) ? fshl(X, *, ShAmt) : X --> X
4931     // (ShAmt == 0) ? fshr(*, X, ShAmt) : X --> X
4932     if (match(TrueVal, isFsh) && FalseVal == X && CmpLHS == ShAmt)
