4939     // that would not preserve the poison safety of the original code.
4940     auto isRotate =
4941         m_CombineOr(m_FShl(m_Value(X), m_Deferred(X), m_Value(ShAmt)),
4942                     m_FShr(m_Value(X), m_Deferred(X), m_Value(ShAmt)));
4943     // (ShAmt == 0) ? X : fshl(X, X, ShAmt) --> fshl(X, X, ShAmt)
4944     // (ShAmt == 0) ? X : fshr(X, X, ShAmt) --> fshr(X, X, ShAmt)
4945     if (match(FalseVal, isRotate) && TrueVal == X && CmpLHS == ShAmt &&
4946         Pred == ICmpInst::ICMP_EQ)
4947       return FalseVal;
4948 
4949     // X == 0 ? abs(X) : -abs(X) --> -abs(X)
4950     // X == 0 ? -abs(X) : abs(X) --> abs(X)
4951     if (match(TrueVal, m_Intrinsic<Intrinsic::abs>(m_Specific(CmpLHS))) &&
4952         match(FalseVal, m_Neg(m_Intrinsic<Intrinsic::abs>(m_Specific(CmpLHS)))))
4953       return FalseVal;
4954     if (match(TrueVal,
4955               m_Neg(m_Intrinsic<Intrinsic::abs>(m_Specific(CmpLHS)))) &&
4956         match(FalseVal, m_Intrinsic<Intrinsic::abs>(m_Specific(CmpLHS))))
4957       return FalseVal;
