4961   // the arms of the select. See if substituting this value into the arm and
4962   // simplifying the result yields the same value as the other arm.
4963   if (Pred == ICmpInst::ICMP_EQ) {
4964     if (CmpLHS->getType()->isIntOrIntVectorTy() ||
4965         canReplacePointersIfEqual(CmpLHS, CmpRHS, Q.DL))
4966       if (Value *V = simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, TrueVal,
4967                                                    FalseVal, Q, MaxRecurse))
4968         return V;
4969     if (CmpLHS->getType()->isIntOrIntVectorTy() ||
4970         canReplacePointersIfEqual(CmpRHS, CmpLHS, Q.DL))
4971       if (Value *V = simplifySelectWithEquivalence({{CmpRHS, CmpLHS}}, TrueVal,
4972                                                    FalseVal, Q, MaxRecurse))
4973         return V;
4974 
4975     Value *X;
4976     Value *Y;
4977     // select((X | Y) == 0 ?  X : 0) --> 0 (commuted 2 ways)
4978     if (match(CmpLHS, m_Or(m_Value(X), m_Value(Y))) &&
4979         match(CmpRHS, m_Zero())) {
4980       // (X | Y) == 0 implies X == 0 and Y == 0.
4981       if (Value *V = simplifySelectWithEquivalence(
4982               {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
4983         return V;
4984     }
4985 
4986     // select((X & Y) == -1 ?  X : -1) --> -1 (commuted 2 ways)
4987     if (match(CmpLHS, m_And(m_Value(X), m_Value(Y))) &&
4988         match(CmpRHS, m_AllOnes())) {
4989       // (X & Y) == -1 implies X == -1 and Y == -1.
4990       if (Value *V = simplifySelectWithEquivalence(
4991               {{X, CmpRHS}, {Y, CmpRHS}}, TrueVal, FalseVal, Q, MaxRecurse))
4992         return V;
4993     }
4994   }
4995 
4996   return nullptr;
