4999 /// Try to simplify a select instruction when its condition operand is a
5000 /// floating-point comparison.
5001 static Value *simplifySelectWithFCmp(Value *Cond, Value *T, Value *F,
5002                                      const SimplifyQuery &Q,
5003                                      unsigned MaxRecurse) {
5004   CmpPredicate Pred;
5005   Value *CmpLHS, *CmpRHS;
5006   if (!match(Cond, m_FCmp(Pred, m_Value(CmpLHS), m_Value(CmpRHS))))
5007     return nullptr;
5008   FCmpInst *I = cast<FCmpInst>(Cond);
5009 
5010   bool IsEquiv = I->isEquivalence();
5011   if (I->isEquivalence(/*Invert=*/true)) {
5012     std::swap(T, F);
5013     Pred = FCmpInst::getInversePredicate(Pred);
5014     IsEquiv = true;
5015   }
5016 
5017   // This transforms is safe if at least one operand is known to not be zero.
5018   // Otherwise, the select can change the sign of a zero operand.
5019   if (IsEquiv) {
5020     if (Value *V = simplifySelectWithEquivalence({{CmpLHS, CmpRHS}}, T, F, Q,
5021                                                  MaxRecurse))
5022       return V;
5023     if (Value *V = simplifySelectWithEquivalence({{CmpRHS, CmpLHS}}, T, F, Q,
5024                                                  MaxRecurse))
5025       return V;
5026   }
5027 
5028   // Canonicalize CmpLHS to be T, and CmpRHS to be F, if they're swapped.
5029   if (CmpLHS == F && CmpRHS == T)
5030     std::swap(CmpLHS, CmpRHS);
5031 
5032   if (CmpLHS != T || CmpRHS != F)
5033     return nullptr;
5034 
5035   // This transform is also safe if we do not have (do not care about) -0.0.
5036   if (Q.CxtI && isa<FPMathOperator>(Q.CxtI) && Q.CxtI->hasNoSignedZeros()) {
5037     // (T == F) ? T : F --> F
5038     if (Pred == FCmpInst::FCMP_OEQ)
5039       return F;
5040 
5041     // (T != F) ? T : F --> T
5042     if (Pred == FCmpInst::FCMP_UNE)
5043       return T;
5044   }
5045 
5046   return nullptr;
5047 }
