5049 /// Look for the following pattern and simplify %to_fold to %identicalPhi.
5050 /// Here %phi, %to_fold and %phi.next perform the same functionality as
5051 /// %identicalPhi and hence the select instruction %to_fold can be folded
5052 /// into %identicalPhi.
5053 ///
5054 /// BB1:
5055 ///   %identicalPhi = phi [ X, %BB0 ], [ %identicalPhi.next, %BB1 ]
5056 ///   %phi = phi [ X, %BB0 ], [ %phi.next, %BB1 ]
5057 ///   ...
5058 ///   %identicalPhi.next = select %cmp, %val, %identicalPhi
5059 ///                      (or select %cmp, %identicalPhi, %val)
5060 ///   %to_fold = select %cmp2, %identicalPhi, %phi
5061 ///   %phi.next = select %cmp, %val, %to_fold
5062 ///             (or select %cmp, %to_fold, %val)
5063 ///
5064 /// Prove that %phi and %identicalPhi are the same by induction:
5065 ///
5066 /// Base case: Both %phi and %identicalPhi are equal on entry to the loop.
5067 /// Inductive case:
5068 /// Suppose %phi and %identicalPhi are equal at iteration i.
5069 /// We look at their values at iteration i+1 which are %phi.next and
5070 /// %identicalPhi.next. They would have become different only when %cmp is
5071 /// false and the corresponding values %to_fold and %identicalPhi differ
5072 /// (similar reason for the other "or" case in the bracket).
5073 ///
5074 /// The only condition when %to_fold and %identicalPh could differ is when %cmp2
5075 /// is false and %to_fold is %phi, which contradicts our inductive hypothesis
5076 /// that %phi and %identicalPhi are equal. Thus %phi and %identicalPhi are
5077 /// always equal at iteration i+1.
5078 bool isSelectWithIdenticalPHI(PHINode &PN, PHINode &IdenticalPN) {
5079   if (PN.getParent() != IdenticalPN.getParent())
5080     return false;
5081   if (PN.getNumIncomingValues() != 2)
5082     return false;
5083 
5084   // Check that only the backedge incoming value is different.
5085   unsigned DiffVals = 0;
5086   BasicBlock *DiffValBB = nullptr;
5087   for (unsigned i = 0; i < 2; i++) {
5088     BasicBlock *PredBB = PN.getIncomingBlock(i);
5089     if (PN.getIncomingValue(i) !=
5090         IdenticalPN.getIncomingValueForBlock(PredBB)) {
5091       DiffVals++;
5092       DiffValBB = PredBB;
5093     }
5094   }
5095   if (DiffVals != 1)
5096     return false;
5097   // Now check that the backedge incoming values are two select
5098   // instructions with the same condition. Either their true
5099   // values are the same, or their false values are the same.
5100   auto *SI = dyn_cast<SelectInst>(PN.getIncomingValueForBlock(DiffValBB));
5101   auto *IdenticalSI =
5102       dyn_cast<SelectInst>(IdenticalPN.getIncomingValueForBlock(DiffValBB));
5103   if (!SI || !IdenticalSI)
5104     return false;
5105   if (SI->getCondition() != IdenticalSI->getCondition())
5106     return false;
